app = Flask(__name__)

# Secure configuration
MODEL_PATH = 'spam_model.pkl'
ALLOWED_CHARS = re.compile(r'^[a-zA-Z0-9\s\.\,\!\?\;\:\-\(\)\[\]\{\}\/\_\+\=\*\&\%\$\#\@\^\`\~\<\>]+$')
MAX_TEXT_LENGTH = 10000
MAX_FEATURES = 5000

